mapper.insert:
INSERT INTO reminder (
    user_medicine_id, dosage, reminder_time,
    days_of_week, start_date, end_date, status
) VALUES (
             #{userMedicineId}, #{dosage}, #{reminderTime},
             #{daysOfWeek}, #{startDate}, #{endDate}, #{status}
         )

mapper.select:
SELECT * FROM reminder
WHERE openid = #{openid}
AND status IN (0, 1)   
AND start_date <= #{todayDate}
AND end_date >= #{todayDate}
AND FIND_IN_SET(#{todayWeek}, days_of_week)
ORDER BY reminder_time

SELECT * FROM reminder
WHERE openid = #{openid}
AND status IN (0, 1)          
AND end_date >= #{today}       
ORDER BY start_date, reminder_time
